   284→func urlMatch(specs []string, target string, signatureType plugins.SignatureType) (bool, error) {
   285→	targetURL, err := url.Parse(target)
   286→	if err != nil {
   287→		return false, err
   288→	}
   289→
   290→	for _, spec := range specs {
   291→		specURL, err := url.Parse(spec)
   292→		if err != nil {
   293→			return false, err
   294→		}
   295→
   296→		if specURL.Scheme == targetURL.Scheme && specURL.Host == targetURL.Host &&
   297→			path.Clean(specURL.RequestURI()) == path.Clean(targetURL.RequestURI()) {
   298→			return true, nil
   299→		}
   300→
   301→		if signatureType != plugins.SignatureTypePrivateGlob {
   302→			continue
   303→		}
   304→
   305→		sp, err := glob.Compile(spec, '/', '.')
   306→		if err != nil {
   307→			return false, err
   308→		}
   309→		if match := sp.Match(target); match {
   310→			return true, nil
   311→		}
   312→	}
   313→	return false, nil
   314→}
