    66→// AppDefaultNavURLDecorateFunc is a DecorateFunc that sets the default nav URL for app plugins.
    67→func AppDefaultNavURLDecorateFunc(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
    68→	if p.IsApp() {
    69→		setDefaultNavURL(p)
    70→	}
    71→	return p, nil
    72→}
