    74→// TemplateDecorateFunc is a DecorateFunc that removes the placeholder for the version and last_update fields.
    75→func TemplateDecorateFunc(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
    76→	// %VERSION% and %TODAY% are valid values, according to the plugin schema
    77→	// but it's meant to be replaced by the build system with the actual version and date.
    78→	// If not, it's the same than not having a version or a date.
    79→	if p.Info.Version == "%VERSION%" {
    80→		p.Info.Version = ""
    81→	}
    82→
    83→	if p.Info.Updated == "%TODAY%" {
    84→		p.Info.Updated = ""
    85→	}
    86→
    87→	return p, nil
    88→}
