   116→// AppChildDecorateFunc is a DecorateFunc that configures child plugins of app plugins.
   117→func AppChildDecorateFunc() DecorateFunc {
   118→	return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
   119→		if p.Parent != nil && p.Parent.IsApp() {
   120→			configureAppChildPlugin(p.Parent, p)
   121→		}
   122→		return p, nil
   123→	}
   124→}
   125→
   126→func configureAppChildPlugin(parent *plugins.Plugin, child *plugins.Plugin) {
   127→	if !parent.IsApp() {
   128→		return
   129→	}
   130→	child.IncludedInAppID = parent.ID
   131→
   132→	// If the child plugin does not have a version, it will inherit the version from the parent.
   133→	// This is to ensure that the frontend can appropriately cache the plugin assets.
   134→	if child.Info.Version == "" {
   135→		child.Info.Version = parent.Info.Version
   136→	}
   137→}
