    31→type KeyRetriever struct {
    32→	cfg *setting.Cfg
    33→	log log.Logger
    34→
    35→	lock    sync.Mutex
    36→	cli     http.Client
    37→	kv      plugins.KeyStore
    38→	hasKeys bool
    39→}
    40→
    41→var _ plugins.KeyRetriever = (*KeyRetriever)(nil)
