    95→func (cfg *Cfg) processPreinstallPlugins(rawInstallPlugins []string, preinstallPlugins map[string]InstallPlugin) {
    96→	// Add the plugins defined in the configuration
    97→	for _, plugin := range rawInstallPlugins {
    98→		parts := strings.Split(plugin, "@")
    99→		id := parts[0]
   100→		version := ""
   101→		url := ""
   102→		if len(parts) > 1 {
   103→			version = parts[1]
   104→			if len(parts) > 2 {
   105→				url = parts[2]
   106→			}
   107→		}
   108→
   109→		preinstallPlugins[id] = InstallPlugin{id, version, url}
   110→	}
   111→}
