    21→// LocalFS is a plugins.FS that allows accessing files on the local file system.
    22→type LocalFS struct {
    23→	// basePath is the basePath that will be prepended to all the files to get their absolute path.
    24→	basePath string
    25→}
    26→
    27→// NewLocalFS returns a new LocalFS that can access any file in the specified base path on the filesystem.
    28→// basePath must use os-specific path separator for Open() to work properly.
    29→func NewLocalFS(basePath string) LocalFS {
    30→	return LocalFS{basePath: basePath}
    31→}
    32→
    33→func (f LocalFS) Type() string {
    34→	return "local"
    35→}
    36→
    37→// fileIsAllowed takes an absolute path to a file and an os.FileInfo for that file, and it checks if access to that
    38→// file is allowed or not. Access to a file is allowed if the file is in the FS's Base() directory, and if it's a
    39→// symbolic link it should not end up outside the plugin's directory.
    40→func (f LocalFS) fileIsAllowed(basePath string, absolutePath string, info os.FileInfo) (bool, error) {
    41→	upperLevelPrefix := ".." + string(filepath.Separator)
    42→	if info.Mode()&os.ModeSymlink == os.ModeSymlink {
    43→		symlinkPath, err := filepath.EvalSymlinks(absolutePath)
    44→		if err != nil {
    45→			return false, err
    46→		}
    47→
    48→		symlink, err := os.Stat(symlinkPath)
    49→		if err != nil {
    50→			return false, err
    51→		}
    52→
    53→		// verify that symlinked file is within plugin directory
    54→		p, err := filepath.Rel(basePath, symlinkPath)
    55→		if err != nil {
    56→			return false, err
    57→		}
    58→		if p == ".." || strings.HasPrefix(p, upperLevelPrefix) {
    59→			return false, fmt.Errorf("file '%s' not inside of plugin directory", p)
    60→		}
    61→
    62→		// skip adding symlinked directories
    63→		if symlink.IsDir() {
    64→			return false, nil
    65→		}
    66→	}
    67→
    68→	// skip directories
    69→	if info.IsDir() {
    70→		return false, nil
    71→	}
    72→
    73→	// verify that file is within plugin directory
    74→	file, err := filepath.Rel(f.Base(), absolutePath)
    75→	if err != nil {
    76→		return false, err
    77→	}
    78→	if strings.HasPrefix(file, upperLevelPrefix) {
    79→		return false, fmt.Errorf("file '%s' not inside of plugin directory", file)
    80→	}
    81→	return true, nil
    82→}
