    88→// walkFunc returns a filepath.WalkFunc that accumulates absolute file paths into acc by walking over f.Base().
    89→// f.fileIsAllowed is used as WalkFunc, see its documentation for more information on which files are collected.
    90→func (f LocalFS) walkFunc(basePath string, acc map[string]struct{}) filepath.WalkFunc {
    91→	return func(path string, info os.FileInfo, err error) error {
    92→		if err != nil {
    93→			return err
    94→		}
    95→		ok, err := f.fileIsAllowed(basePath, path, info)
    96→		if err != nil {
    97→			return err
    98→		}
    99→		if !ok {
   100→			return nil
   101→		}
   102→		acc[path] = struct{}{}
   103→		return nil
   104→	}
   105→}
