   107→// Open opens the specified file on the local filesystem.
   108→// The provided name must be a relative file name that uses os-specific path separators.
   109→// The function returns the corresponding fs.File for accessing the file on the local filesystem.
   110→// If a nil error is returned, the caller should take care of calling Close() the returned fs.File.
   111→// If the file does not exist, ErrFileNotExist is returned.
   112→func (f LocalFS) Open(name string) (fs.File, error) {
   113→	cleanPath, err := util.CleanRelativePath(name)
   114→	if err != nil {
   115→		return nil, err
   116→	}
   117→	basePath := f.Base()
   118→	absFn := filepath.Join(basePath, cleanPath)
   119→	finfo, err := os.Stat(absFn)
   120→	if err != nil {
   121→		return nil, ErrFileNotExist
   122→	}
   123→	// Make sure access to the file is allowed (symlink check, etc)
   124→	ok, err := f.fileIsAllowed(basePath, absFn, finfo)
   125→	if err != nil {
   126→		return nil, err
   127→	}
   128→	if !ok {
   129→		return nil, ErrFileNotExist
   130→	}
   131→	return &LocalFile{path: absFn}, nil
   132→}
   133→
   134→// Base returns the base path for the LocalFS.
   135→// The returned string uses os-specific path separator.
   136→func (f LocalFS) Base() string {
   137→	return f.basePath
   138→}
   139→
   140→// Files returns a slice of all the relative file paths on the LocalFS.
   141→// The returned strings can be passed to Open() to open those files.
   142→// The returned strings use os-specific path separator.
   143→func (f LocalFS) Files() ([]string, error) {
   144→	// Accumulate all files into filesMap by calling f.collectFilesFunc, which will write into the accumulator.
   145→	// Those are absolute because filepath.Walk uses absolute file paths.
   146→	absFilePaths := make(map[string]struct{})
   147→	if err := filepath.Walk(f.basePath, f.walkFunc(f.Base(), absFilePaths)); err != nil {
   148→		return nil, fmt.Errorf("walk: %w", err)
   149→	}
