   257→func DirAsLocalSources(cfg *config.PluginManagementCfg, pluginsPath string, class plugins.Class) ([]*LocalSource, error) {
   258→	if pluginsPath == "" {
   259→		return []*LocalSource{}, errors.New("plugins path not configured")
   260→	}
   261→
   262→	// It's safe to ignore gosec warning G304 since the variable part of the file path comes from a configuration
   263→	// variable.
   264→	// nolint:gosec
   265→	d, err := os.ReadDir(pluginsPath)
   266→	if err != nil {
   267→		return []*LocalSource{}, errors.New("failed to open plugins path")
   268→	}
   269→
   270→	var pluginDirs []string
   271→	for _, dir := range d {
   272→		if dir.IsDir() || dir.Type()&os.ModeSymlink == os.ModeSymlink {
   273→			pluginDirs = append(pluginDirs, filepath.Join(pluginsPath, dir.Name()))
   274→		}
   275→	}
   276→	slices.Sort(pluginDirs)
   277→
   278→	sources := make([]*LocalSource, len(pluginDirs))
   279→	for i, dir := range pluginDirs {
   280→		if cfg.DevMode {
   281→			sources[i] = NewUnsafeLocalSource(class, []string{dir})
   282→		} else {
   283→			sources[i] = NewLocalSource(class, []string{dir})
   284→		}
   285→	}
   286→
   287→	return sources, nil
   288→}
